const PageContact=(()=>{function init(){initForm("contact-form","/api/contact",LanguageEngine.t("contact_form_success"));initForm("prayer-form","/api/prayer",LanguageEngine.t("prayer_form_success"))}function initForm(formId,endpoint,successMsg){const form=document.getElementById(formId);if(!form)return;form.addEventListener("submit",function(e){e.preventDefault();const btn=form.querySelector('[type="submit"]');const errorEl=form.querySelector(".form-error-msg");const data={};form.querySelectorAll("[name]").forEach(el=>{data[el.name]=el.value});if(errorEl)errorEl.classList.remove("show");btn.disabled=true;btn.textContent=LanguageEngine.t("loading");fetch(endpoint,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(data)}).then(r=>{btn.disabled=false;btn.textContent=LanguageEngine.t("contact_form_submit");if(r.ok){form.reset();showSuccess(successMsg)}else{if(errorEl){errorEl.textContent=LanguageEngine.t("error_generic");errorEl.classList.add("show")}}}).catch(()=>{btn.disabled=false;btn.textContent=LanguageEngine.t("contact_form_submit");if(errorEl){errorEl.textContent=LanguageEngine.t("error_network");errorEl.classList.add("show")}})})}function showSuccess(msg){const popup=document.querySelector(".success-popup");if(!popup)return;const msgEl=popup.querySelector("[data-success-msg]");if(msgEl)msgEl.textContent=msg;popup.classList.add("show");setTimeout(()=>popup.classList.remove("show"),4e3);const closeBtn=popup.querySelector(".success-popup-btn");if(closeBtn){closeBtn.addEventListener("click",()=>popup.classList.remove("show"))}popup.addEventListener("click",e=>{if(e.target===popup)popup.classList.remove("show")})}return{init:init}})();window.PageContact=PageContact;